function fmtTimestamp(iso, timezone) {
  const d = new Date(iso);
  if (isNaN(d.getTime())) return iso || '';
  try {
    return d.toLocaleString('en-US', {
      timeZone: timezone || 'UTC',
      month: 'numeric', day: 'numeric', year: 'numeric',
      hour: 'numeric', minute: '2-digit', second: '2-digit',
      hour12: false,
    });
  } catch {
    return d.toISOString();
  }
}

function normalizeHeader(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function toSheetValue(value) {
  if (value === null || value === undefined) return '';
  return String(value);
}

function similarity(a, b) {
  if (a === b) return 1;
  if (a.length < 2 || b.length < 2) return 0;
  if (a.length > b.length) { const t = a; a = b; b = t; }
  const bBigrams = new Map();
  for (let i = 0; i < b.length - 1; i++) {
    const bg = b.slice(i, i + 2);
    bBigrams.set(bg, (bBigrams.get(bg) || 0) + 1);
  }
  let intersectionSize = 0;
  const bCopy = new Map(bBigrams);
  for (let i = 0; i < a.length - 1; i++) {
    const bg = a.slice(i, i + 2);
    const cnt = bCopy.get(bg) || 0;
    if (cnt > 0) { bCopy.set(bg, cnt - 1); intersectionSize++; }
  }
  const aLen = a.length - 1;
  const bLen = b.length - 1;
  const dice = (2 * intersectionSize) / (aLen + bLen);
  const containment = intersectionSize / aLen;
  return Math.max(dice, containment);
}

function findHeader(key, headerByNormalized, threshold) {
  const normalizedKey = normalizeHeader(key);
  if (headerByNormalized.has(normalizedKey)) return headerByNormalized.get(normalizedKey);
  let bestScore = 0;
  let bestHeader = null;
  for (const [normHeader, origHeader] of headerByNormalized) {
    const score = similarity(normalizedKey, normHeader);
    if (score > bestScore) {
      bestScore = score;
      bestHeader = origHeader;
    }
  }
  return bestScore >= threshold ? bestHeader : null;
}

const FUZZY_THRESHOLD = 0.75;

const payload = $('Webhook Submitted').first().json.body;
const sheetRow = $('Read Sheet Headers Submitted').first().json;
const headers = Object.keys(sheetRow).filter((header) => header !== 'row_number');
const headerByNormalized = new Map(headers.map((header) => [normalizeHeader(header), header]));

const row = {};
const timestampHeader = headers[0] || 'Timestamp';
const timestampValue = fmtTimestamp(payload.original_submitted_at || payload.submitted_at || payload.timestamp, payload.location_timezone);
row[timestampHeader] = timestampValue;
row["response_id"] = payload.response_id;

for (const [key, value] of Object.entries(payload.record || {})) {
  const matchedHeader = findHeader(key, headerByNormalized, FUZZY_THRESHOLD) || key;
  row[matchedHeader] = toSheetValue(value);
}

if (payload.media?.completion_signature) {
  const signatureHeader = findHeader('signature', headerByNormalized, FUZZY_THRESHOLD) || 'signature';
  row[signatureHeader] = payload.media.completion_signature;
}

if (payload.media?.completion_selfie) {
  const selfieHeader = findHeader('selfie', headerByNormalized, FUZZY_THRESHOLD) || 'selfie';
  row[selfieHeader] = payload.media.completion_selfie;
}

return [{ json: row }];

